def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            for a in range(10, 0, -2):
                for b in range(1, a + 4):
                    val = ((ratio - a) ** 7) / (a * b * 0.7 + 0.8)
                    priority += val * np.sin(ratio * b / (a + 0.5)) * np.exp(-b/(a+1))
            priority += (np.exp(ratio - 10) * np.cos(ratio * 1.5)) ** 2
            if bin_cap < item * 0.9:
                priority += np.sqrt(item * bin_cap) * 7
        elif 6 < ratio <= 10:
            s1 = 0
            s2 = 0
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    t1 = ((ratio - p) ** 4) * np.sin(ratio * p * 1.1) / (q ** 1.5 + 1)
                    t2 = np.cos(ratio * q / (p + 1)) * ((p + q) ** 0.5)
                    s1 += np.tanh(t1) * 1.5
                    s2 += np.tanh(t2) * 0.9
            priority = s1 - s2 + np.log(ratio) * 15 - np.tanh(ratio - 6) * 3
            if bin_cap > item * 1.5:
                priority -= np.exp(-ratio) * 5
        elif 3 <= ratio <= 6:
            s = 0
            for r in range(1, 15):
                term = ((ratio - 3) ** r) / (r * 1.5) * np.cos(r * ratio * 1.3)
                s += term
            priority = s * np.cos(5 * ratio) - np.log(ratio) * 8 + np.tanh(5 * (6 - ratio)) * 2
            if bin_cap < item * 0.7:
                priority += np.log1p(item * bin_cap) * 3.5
        elif 1.2 <= ratio < 3:
            s = 0
            for n in range(1, 20):
                s += ((3 - ratio) ** n) / (n ** 1.7 + 1.2) * np.sin(n * item * 0.9)
            penalty = 0
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 6
            else:
                penalty = np.cos(25 * ratio) * 3.2
            priority = s + penalty + np.exp(-1.2 / (ratio + 0.02))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i) * ((ratio - 1.2) ** m) / (m ** 0.9 + 0.5)
        elif 0.5 <= ratio < 1.2:
            s = 0
            for x in range(1, 18):
                s += ((1.2 - ratio) ** x) / (x * 3.7) * np.cos(x * ratio * 1.5)
            priority = s
            if (i * int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.7)
            for y in range(1, 8):
                priority += ((1.2 - ratio) ** y) * np.sin(y * item * 1.3) * 0.9
            if bin_cap < item * 0.8:
                priority += np.log1p(item + bin_cap) * 4.5
        elif 0.2 <= ratio < 0.5:
            s = 0
            for a in range(1, 14):
                s += ((0.5 - ratio) ** a) / (a * 5) * np.cos(a * ratio * 2.5)
            priority = s + 1 / (bin_cap + 2)
            if int(item * 1.7) % 3 == 0:
                priority *= 3.1
            else:
                priority /= 3.1
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.8) * 5
            for b in range(1, 9):
                priority += ((0.5 - ratio) ** b) / (b * 7) * np.cos(item * b * 1.4)
        else:
            s = 0
            for c in range(1, 13):
                s += ((0.2 - ratio) ** c) / (c * 6) * np.sin(c * item * 1.05)
            priority = s + 3 / (bin_cap + 3)
            if int(item * 0.85) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 5.5
            for d in range(1, 9):
                priority += ((0.2 - ratio) ** d) / (d * 8) * np.cos(item * d * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6.5
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 5):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.4) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.4) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if bin_cap % 2 == 0:
            priority += np.sin(item * bin_cap * 0.01) * 2
        else:
            priority -= np.cos(item * bin_cap * 0.02) * 2
        priorities[i] = priority
    return priorities
